use crossterm::event::KeyCode;
use ratatui::{
    layout::{Constraint, Layout, Rect},
    style::Modifier,
    text::{Line, Span, Text},
    widgets::{Block, Borders, Paragraph, Wrap},
};

use crate::app::engine::Engine;
use crate::app::state::CompletionCard;
use crate::content::command_info::command_blurb;

use super::{
    button::Button,
    clickable_list::ClickableList,
    cluster_view::ClusterView,
    constants::UiStyle,
    traits::Screen,
    ui_frame::UiFrame,
    ui_action::UiAction,
    widgets::{
        default_block, difficulty_badge, domain_tag, ellipsize, footer_help_text, mode_badge,
        readiness_segments, step_type_badge, titled_block,
    },
};

const WIDE_TERMINAL_THRESHOLD: u16 = 120;

pub struct LearningScreen {
    pub command_input: String,
    pub status: String,
    pub output_log: Vec<String>,
    pub hint_message: Option<String>,
    pub completion_card: Option<CompletionCard>,
    pub tab_index: usize,
}

impl LearningScreen {
    pub fn new(status: String) -> Self {
        Self {
            command_input: String::new(),
            status,
            output_log: vec!["CKA Coach terminal started (/bin/zsh).".to_string()],
            hint_message: None,
            completion_card: None,
            tab_index: 0,
        }
    }
}

impl Screen for LearningScreen {
    fn update(&mut self, _engine: &Engine) -> anyhow::Result<()> {
        Ok(())
    }

    fn render(&mut self, frame: &mut UiFrame<'_, '_>, engine: &Engine, area: Rect) -> anyhow::Result<()> {
        let zones = Layout::vertical([
            Constraint::Length(3),
            Constraint::Min(0),
            Constraint::Length(3),
            Constraint::Length(4),
        ])
        .split(area);

        render_header(frame, zones[0], engine);

        if zones[1].width >= WIDE_TERMINAL_THRESHOLD {
            let split =
                Layout::horizontal([Constraint::Percentage(70), Constraint::Percentage(30)])
                    .split(zones[1]);
            render_main_feed(
                frame,
                split[0],
                engine,
                &self.status,
                &self.output_log,
                self.hint_message.as_deref(),
                self.completion_card.as_ref(),
            );
            render_activity_rail(
                frame,
                split[1],
                engine.current_step().run_commands.as_slice(),
                self.hint_message.as_deref(),
                self.completion_card.as_ref(),
                &self.status,
            );
        } else {
            render_main_feed(
                frame,
                zones[1],
                engine,
                &self.status,
                &self.output_log,
                self.hint_message.as_deref(),
                self.completion_card.as_ref(),
            );
        }

        render_action_row(frame, zones[2], self.command_input.is_empty());
        render_command_bar(frame, zones[3], &self.command_input, &self.status);
        Ok(())
    }

    fn handle_key_events(
        &mut self,
        key_event: crossterm::event::KeyEvent,
        _engine: &Engine,
    ) -> Option<UiAction> {
        use crossterm::event::KeyCode;
        match key_event.code {
            KeyCode::Enter => {
                let input = self.command_input.trim().to_string();
                self.command_input.clear();

                if input.is_empty() {
                    return Some(UiAction::None);
                }

                if let Some(command) = input.strip_prefix("! ") {
                    return Some(UiAction::ForceRunCommand(command.trim().to_string()));
                }

                if input.starts_with('/') {
                    let mut parts = input.split_whitespace();
                    let cmd = parts.next().unwrap_or_default();
                    return Some(match cmd {
                        "/quit" => UiAction::Quit,
                        "/new" => UiAction::NewSession,
                        "/next" => UiAction::NextStep,
                        "/prev" => UiAction::PrevStep,
                        "/back" => UiAction::JumpBack,
                        "/recommended" => UiAction::JumpRecommended,
                        "/verify" => UiAction::Verify,
                        "/hint" => UiAction::Hint,
                        "/suggest" => UiAction::Suggest(parts.next().and_then(|n| n.parse().ok())),
                        "/clear" => UiAction::ClearLog,
                        "/help" => UiAction::ShowHelp,
                        "/shell" => match parts.next() {
                            Some(mode) => UiAction::SetShellMode(mode.to_string()),
                            None => UiAction::ShowShellMode,
                        },
                        _ => UiAction::None,
                    });
                }

                Some(UiAction::RunCommand(input))
            }
            KeyCode::Backspace => {
                self.command_input.pop();
                self.tab_index = 0;
                Some(UiAction::None)
            }
            KeyCode::Esc => {
                self.command_input.clear();
                Some(UiAction::None)
            }
            KeyCode::Char(c) => {
                self.command_input.push(c);
                self.tab_index = 0;
                Some(UiAction::None)
            }
            _ => None,
        }
    }

    fn footer_help(&self) -> String {
        footer_help_text(&self.command_input)
    }

    fn footer_spans(&self) -> Vec<(String, String)> {
        vec![
            ("V".to_string(), "Verify".to_string()),
            ("H".to_string(), "Hint".to_string()),
            ("Enter".to_string(), "Run".to_string()),
            ("/help".to_string(), "Commands".to_string()),
        ]
    }
}

fn render_header(frame: &mut UiFrame<'_, '_>, area: Rect, engine: &Engine) {
    let step = engine.current_step();
    let block = default_block();
    let inner = block.inner(area);
    frame.render_widget(block, area);

    let (bar_on, bar_off) = readiness_segments(engine.readiness, 12);

    let step_chip = format!(
        "[STEP {:02}/{:02}]",
        engine.current_index + 1,
        engine.steps.len()
    );

    let title = ellipsize(&step.title, inner.width.saturating_sub(4) as usize);

    let row1 = Line::from(vec![
        Span::styled(" CKA BUDDY ", UiStyle::HEADER.add_modifier(Modifier::BOLD)),
        Span::styled(" [", UiStyle::MUTED),
        Span::styled(bar_on, UiStyle::OK),
        Span::styled(bar_off, UiStyle::MUTED),
        Span::styled("] ", UiStyle::MUTED),
        Span::styled(format!("{:>3}%  ", engine.readiness), UiStyle::TEXT_PRIMARY),
        Span::styled(step_chip, UiStyle::HIGHLIGHT),
        Span::raw(" "),
        step_type_badge(&step.step_type),
        Span::raw(" "),
        difficulty_badge(&step.difficulty),
    ]);

    let mut row2_spans = vec![
        Span::raw("  "),
        Span::styled(title, UiStyle::TEXT_PRIMARY.add_modifier(Modifier::BOLD)),
        Span::raw("  "),
    ];
    for domain in &step.domains {
        row2_spans.push(domain_tag(domain));
        row2_spans.push(Span::raw(" "));
    }

    let header = vec![row1, Line::from(row2_spans)];
    frame.render_widget(Paragraph::new(header), inner);
}

fn render_main_feed(
    frame: &mut UiFrame<'_, '_>,
    area: Rect,
    engine: &Engine,
    _status: &str,
    output_log: &[String],
    hint_message: Option<&str>,
    completion_card: Option<&CompletionCard>,
) {
    let step = engine.current_step();
    let command_count = step.run_commands.len().min(5) as u16;
    // Each command now takes 2 lines (blurb + command), so double the count
    let step_panel_height =
        (6 + command_count * 2).clamp(6, area.height.saturating_sub(8).max(6));

    let chunks =
        Layout::vertical([Constraint::Length(step_panel_height), Constraint::Min(4)]).split(area);

    render_step_panel(frame, chunks[0], engine);
    render_terminal_feed(frame, chunks[1], output_log, hint_message, completion_card);
}

fn render_step_panel(frame: &mut UiFrame<'_, '_>, area: Rect, engine: &Engine) {
    let step = engine.current_step();
    let block = titled_block("Step");
    let inner = block.inner(area);
    frame.render_widget(block, area);

    let mut lines = vec![
        Line::from(vec![
            Span::styled("  Objective: ", UiStyle::MUTED),
            Span::styled(
                step.objective.clone(),
                UiStyle::TEXT_PRIMARY.add_modifier(Modifier::BOLD),
            ),
        ]),
        Line::from(vec![Span::styled(
            format!(
                "  {} min  |  {}  |  {}",
                step.timebox_min,
                step.difficulty,
                step.domains.join(", ")
            ),
            UiStyle::MUTED,
        )]),
        Line::from(""),
    ];

    if step.run_commands.is_empty() {
        lines.push(Line::from(Span::styled(
            "  (no suggested commands — use objective + docs)",
            UiStyle::MUTED,
        )));
        frame.render_widget(Paragraph::new(lines).wrap(Wrap { trim: true }), inner);
    } else {
        lines.push(Line::from(Span::styled("  Runbook:", UiStyle::MUTED)));
        for (idx, cmd) in step.run_commands.iter().take(5).enumerate() {
            let blurb = command_blurb(cmd);
            lines.push(Line::from(vec![
                Span::styled(format!("  [{:>1}] ", idx + 1), UiStyle::MUTED),
                Span::styled(blurb, UiStyle::TEXT_PRIMARY),
            ]));
        }

        frame.render_widget(Paragraph::new(lines).wrap(Wrap { trim: true }), inner);

        let list_top = inner.y.saturating_add(4);
        let available_rows = inner.bottom().saturating_sub(list_top);
        let rows = step.run_commands.len().min(5).min(available_rows as usize);
        if rows > 0 {
            let list_area = Rect::new(inner.x, list_top, inner.width, rows as u16);
            let items = step
                .run_commands
                .iter()
                .take(rows)
                .map(|cmd| cmd.clone())
                .collect::<Vec<_>>();
            let actions = items
                .iter()
                .map(|cmd| UiAction::SetCommandInput(cmd.clone()))
                .collect::<Vec<_>>();
            let list = ClickableList::new(items, actions)
                .style(UiStyle::COMMAND)
                .marker("      ");
            frame.render_interactive_widget(list, list_area);
        }
    }
}

fn render_terminal_feed(
    frame: &mut UiFrame<'_, '_>,
    area: Rect,
    output_log: &[String],
    hint_message: Option<&str>,
    completion_card: Option<&CompletionCard>,
) {
    let block = titled_block("Terminal");
    let inner = block.inner(area);
    frame.render_widget(block, area);

    let mut lines = Vec::new();
    let max_lines = 90usize;
    let start = output_log.len().saturating_sub(max_lines);
    for entry in &output_log[start..] {
        lines.push(Line::from(Span::styled(
            format!("  {entry}"),
            UiStyle::TEXT_SECONDARY,
        )));
    }

    if let Some(hint) = hint_message {
        lines.push(Line::from(""));
        lines.push(Line::from(vec![
            Span::styled("  ● Hint: ", UiStyle::WARNING.add_modifier(Modifier::BOLD)),
            Span::styled(
                hint.to_string(),
                UiStyle::WARNING.add_modifier(Modifier::ITALIC),
            ),
        ]));
    }

    if let Some(card) = completion_card {
        lines.push(Line::from(""));
        lines.push(Line::from(vec![
            Span::styled("  ✓ ", UiStyle::OK.add_modifier(Modifier::BOLD)),
            Span::styled(card.done.clone(), UiStyle::OK.add_modifier(Modifier::BOLD)),
        ]));
        for item in &card.what_changed {
            lines.push(Line::from(vec![
                Span::raw("    "),
                Span::styled(item.clone(), UiStyle::OK),
            ]));
        }
        if !card.next_commands.is_empty() {
            lines.push(Line::from(vec![
                Span::styled("    Next: ", UiStyle::MUTED),
                Span::styled(card.next_commands.join(" | "), UiStyle::MUTED),
            ]));
        }
    }

    let scroll = lines.len().saturating_sub(inner.height as usize) as u16;
    frame.render_widget(
        Paragraph::new(Text::from(lines))
            .wrap(Wrap { trim: false })
            .scroll((scroll, 0)),
        inner,
    );
}

fn status_badge(status: &str) -> (&'static str, ratatui::style::Style) {
    let normalized = status.trim();
    let lower = normalized.to_ascii_lowercase();

    let (label, style) = if lower.starts_with("error")
        || lower.starts_with("fail")
        || lower.contains("failed")
        || lower.contains("error")
    {
        ("ERROR", UiStyle::ERROR)
    } else if lower.starts_with("warn") || lower.contains("warning") {
        ("WARN", UiStyle::WARNING)
    } else if lower.starts_with("ok")
        || lower.starts_with("done")
        || lower.starts_with("success")
        || lower.contains("complete")
        || lower.contains("ready")
    {
        ("SUCCESS", UiStyle::OK)
    } else {
        ("INFO", UiStyle::HIGHLIGHT)
    };

    (label, style.add_modifier(Modifier::BOLD))
}

fn render_activity_rail(
    frame: &mut UiFrame<'_, '_>,
    area: Rect,
    run_commands: &[String],
    hint_message: Option<&str>,
    completion_card: Option<&CompletionCard>,
    status: &str,
) {
    let block = titled_block("Activity");
    let inner = block.inner(area);
    frame.render_widget(block, area);

    let sections = Layout::vertical([Constraint::Min(6), Constraint::Length(6)]).split(inner);

    let cluster = ClusterView::new("CLUSTER", "k8s", run_commands, run_commands.len());
    frame.render_widget(cluster, sections[0]);

    let (status_label, status_style) = status_badge(status);
    let mut lines = vec![Line::from(vec![
        Span::styled("  Status ", UiStyle::MUTED),
        Span::styled(format!("[{status_label}]"), status_style),
    ])];

    if let Some(hint) = hint_message {
        lines.push(Line::from(Span::styled(format!("  {hint}"), UiStyle::WARNING)));
    }

    if let Some(card) = completion_card {
        lines.push(Line::from(Span::styled(format!("  {}", card.done), UiStyle::OK)));
    }

    frame.render_widget(Paragraph::new(lines).wrap(Wrap { trim: true }), sections[1]);
}

fn render_action_row(frame: &mut UiFrame<'_, '_>, area: Rect, enable_hotkeys: bool) {
    if area.height < 3 {
        return;
    }

    let rows = Layout::horizontal([Constraint::Length(14), Constraint::Length(12), Constraint::Min(0)])
        .split(area);

    let verify = {
        let b = Button::new("Verify").on_click(UiAction::Verify).hover_text(Text::from("Run verification checks"));
        if enable_hotkeys { b.hotkey(KeyCode::Char('v')) } else { b }
    };

    let hint = {
        let b = Button::new("Hint").on_click(UiAction::Hint).hover_text(Text::from("Get a contextual hint"));
        if enable_hotkeys { b.hotkey(KeyCode::Char('h')) } else { b }
    };

    frame.render_interactive_widget(verify, rows[0]);
    frame.render_interactive_widget(hint, rows[1]);
}

fn render_command_bar(frame: &mut UiFrame<'_, '_>, area: Rect, command_input: &str, status: &str) {
    if area.height == 0 {
        return;
    }

    let help_text = footer_help_text(command_input);
    let (badge_label, badge_style) = mode_badge(status, command_input);

    if area.height == 1 {
        let compact = Line::from(vec![
            Span::styled(" ❯ ", UiStyle::PROMPT.add_modifier(Modifier::BOLD)),
            Span::styled(command_input.to_string(), UiStyle::TEXT_PRIMARY),
            Span::raw(" "),
            Span::styled(format!("[{badge_label}]"), badge_style),
        ]);
        frame.render_widget(Paragraph::new(compact), area);
        return;
    }

    if area.height == 2 {
        let rows = Layout::vertical([Constraint::Length(1), Constraint::Length(1)]).split(area);
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                format!("  {help_text}"),
                UiStyle::MUTED,
            ))),
            rows[0],
        );

        let compact = Line::from(vec![
            Span::styled("  ❯ ", UiStyle::PROMPT.add_modifier(Modifier::BOLD)),
            Span::styled(command_input.to_string(), UiStyle::TEXT_PRIMARY),
            Span::raw("  "),
            Span::styled(format!("[{badge_label}]"), badge_style),
        ]);
        frame.render_widget(
            Paragraph::new(compact).block(
                Block::default()
                    .borders(Borders::TOP)
                    .border_style(UiStyle::BORDER),
            ),
            rows[1],
        );
        return;
    }

    let bar = Layout::vertical([
        Constraint::Length(1),
        Constraint::Length(1),
        Constraint::Length(2),
    ])
    .split(area);

    frame.render_widget(
        Paragraph::new(Line::from(Span::styled(
            format!("  {help_text}"),
            UiStyle::MUTED,
        ))),
        bar[0],
    );

    frame.render_widget(
        Paragraph::new(Line::from(Span::styled(
            format!("  {status}"),
            UiStyle::TEXT_SECONDARY,
        )))
        .block(
            Block::default()
                .borders(Borders::TOP)
                .border_style(UiStyle::BORDER),
        ),
        bar[1],
    );

    let input_line = Line::from(vec![
        Span::styled("  ❯ ", UiStyle::PROMPT.add_modifier(Modifier::BOLD)),
        Span::styled(command_input.to_string(), UiStyle::TEXT_PRIMARY),
        Span::raw("  "),
        Span::styled(format!("[{badge_label}]"), badge_style),
    ]);

    frame.render_widget(Paragraph::new(input_line), bar[2]);
}

use std::env;
use std::io::{BufRead, BufReader, Write};
use std::net::{TcpListener, TcpStream};
use std::path::Path;
use std::process::Command;

use anyhow::{Context, Result, bail};

use crate::terminal::pty::PtySession;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ShellMode {
    Embedded,
    External,
}

impl ShellMode {
    pub fn as_str(self) -> &'static str {
        match self {
            Self::Embedded => "embedded",
            Self::External => "external",
        }
    }

    pub fn parse(value: &str) -> Option<Self> {
        match value.trim().to_ascii_lowercase().as_str() {
            "embedded" => Some(Self::Embedded),
            "external" => Some(Self::External),
            _ => None,
        }
    }
}

pub struct ShellRouter {
    mode: ShellMode,
    embedded: PtySession,
    terminal_override: Option<String>,
    external: Option<ExternalBridge>,
    external_output: Vec<String>,
}

impl ShellRouter {
    pub fn new(mode: ShellMode, embedded: PtySession, terminal_override: Option<String>) -> Self {
        let external = if mode == ShellMode::External {
            ExternalBridge::new(terminal_override.clone()).ok()
        } else {
            None
        };

        let mut external_output = Vec::new();
        if mode == ShellMode::External && external.is_none() {
            external_output.push(
                "external mode unavailable: could not initialize bridge; switch to /shell embedded"
                    .to_string(),
            );
        }

        Self {
            mode,
            embedded,
            terminal_override,
            external,
            external_output,
        }
    }

    pub fn mode(&self) -> ShellMode {
        self.mode
    }

    pub fn set_mode(&mut self, mode: ShellMode) {
        self.mode = mode;
        if self.mode == ShellMode::External && self.external.is_none() {
            self.external = ExternalBridge::new(self.terminal_override.clone()).ok();
            if self.external.is_none() {
                self.external_output.push(
                    "failed to initialize external bridge; staying unpaired (use /shell embedded)"
                        .to_string(),
                );
            }
        }
    }

    pub fn external_connect_command(&self) -> Option<String> {
        self.external.as_ref().map(ExternalBridge::connect_command)
    }

    pub fn send_line(&mut self, line: &str) -> Result<String> {
        match self.mode {
            ShellMode::Embedded => {
                self.embedded.send_line(line)?;
                Ok(format!("embedded dispatch: {line}"))
            }
            ShellMode::External => {
                let Some(bridge) = self.external.as_mut() else {
                    bail!("external bridge not available; use /shell embedded");
                };

                bridge.poll_accept(&mut self.external_output);

                if !bridge.is_connected() {
                    let msg = format!(
                        "external terminal not connected yet. Run: {}",
                        bridge.connect_command()
                    );
                    self.external_output.push(msg.clone());
                    return Ok(msg);
                }

                bridge.send_line(line).with_context(|| {
                    format!("failed to dispatch command to external bridge: {line}")
                })?;

                let msg = format!("external dispatch: {line}");
                self.external_output.push(msg.clone());
                Ok(msg)
            }
        }
    }

    pub fn drain_output(&mut self) -> Vec<String> {
        match self.mode {
            ShellMode::Embedded => self.embedded.drain_output(),
            ShellMode::External => {
                if let Some(bridge) = self.external.as_mut() {
                    bridge.poll_accept(&mut self.external_output);
                }
                let mut out = Vec::new();
                std::mem::swap(&mut out, &mut self.external_output);
                out
            }
        }
    }
}

struct ExternalBridge {
    listener: TcpListener,
    stream: Option<TcpStream>,
    pin: String,
    terminal: String,
}

impl ExternalBridge {
    fn new(terminal_override: Option<String>) -> Result<Self> {
        let terminal = resolve_terminal_executable(terminal_override)?;
        let listener = TcpListener::bind(("127.0.0.1", 0))?;
        listener.set_nonblocking(true)?;

        Ok(Self {
            listener,
            stream: None,
            pin: generate_pin(),
            terminal,
        })
    }

    fn connect_command(&self) -> String {
        let port = self.listener.local_addr().map(|a| a.port()).unwrap_or(0);
        format!(
            "cargo run -- --shell-connect {} --port {}  # open in {}",
            self.pin, port, self.terminal
        )
    }

    fn is_connected(&self) -> bool {
        self.stream.is_some()
    }

    fn poll_accept(&mut self, output: &mut Vec<String>) {
        if self.stream.is_some() {
            return;
        }

        let Ok((stream, addr)) = self.listener.accept() else {
            return;
        };

        if let Ok(cloned) = stream.try_clone() {
            let mut reader = BufReader::new(cloned);
            let mut auth_line = String::new();
            if reader.read_line(&mut auth_line).is_ok() {
                let expected = format!("PIN {}", self.pin);
                if auth_line.trim() == expected {
                    let _ = stream.set_nonblocking(true);
                    self.stream = Some(stream);
                    output.push(format!("external terminal connected from {addr}"));
                    return;
                }
            }
        }

        output.push("external terminal connection rejected (pin mismatch)".to_string());
    }

    fn send_line(&mut self, line: &str) -> Result<()> {
        let Some(stream) = self.stream.as_mut() else {
            bail!("external bridge not connected")
        };

        if let Err(err) = writeln!(stream, "{line}") {
            self.stream = None;
            bail!("bridge disconnected: {err}");
        }
        stream.flush()?;
        Ok(())
    }
}

pub fn run_shell_connector(pin: &str, port: u16) -> Result<()> {
    let mut stream = TcpStream::connect(("127.0.0.1", port))
        .with_context(|| format!("failed to connect to shell bridge on 127.0.0.1:{port}"))?;
    writeln!(stream, "PIN {pin}")?;
    stream.flush()?;

    println!("Connected to CKA Buddy shell bridge on 127.0.0.1:{port}. Ctrl+C to exit.");

    let mut reader = BufReader::new(stream);
    let shell = default_shell();

    loop {
        let mut line = String::new();
        let n = reader.read_line(&mut line)?;
        if n == 0 {
            println!("Bridge closed.");
            break;
        }

        let command = line.trim();
        if command.is_empty() {
            continue;
        }

        println!("\n$ {command}");
        let status = Command::new(&shell).args(["-lc", command]).status()?;
        println!("[exit: {}]", status.code().unwrap_or(-1));
    }

    Ok(())
}

fn default_shell() -> String {
    env::var("SHELL")
        .ok()
        .filter(|s| !s.trim().is_empty())
        .unwrap_or_else(|| "/bin/zsh".to_string())
}

fn generate_pin() -> String {
    let pid = std::process::id();
    let nanos = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.subsec_nanos())
        .unwrap_or(0);
    format!("{:04}", ((pid + nanos) % 10_000))
}

fn resolve_terminal_executable(terminal_override: Option<String>) -> Result<String> {
    if let Some(exe) = terminal_override.as_deref() {
        return Ok(exe.to_string());
    }

    if let Ok(exe) = env::var("CKA_BUDDY_TERMINAL") {
        if !exe.trim().is_empty() {
            return Ok(exe);
        }
    }

    let candidates = [
        "ghostty",
        "wezterm",
        "alacritty",
        "kitty",
        "gnome-terminal",
        "xterm",
    ];

    for candidate in candidates {
        if is_on_path(candidate) {
            return Ok(candidate.to_string());
        }
    }

    bail!(
        "no supported terminal found (set --terminal or CKA_BUDDY_TERMINAL); tried: ghostty, wezterm, alacritty, kitty, gnome-terminal, xterm"
    )
}

fn is_on_path(bin: &str) -> bool {
    if bin.contains('/') {
        return Path::new(bin).exists();
    }

    let Some(path_var) = env::var_os("PATH") else {
        return false;
    };

    env::split_paths(&path_var).any(|dir| dir.join(bin).exists())
}

