#[derive(Debug, Clone)]
pub struct Button<'a> {
    text: String,
    selected: bool,
    disabled: bool,
    style: Style,
    selected_style: Style,
    block: Option<Block<'a>>,
    on_click: Option<UiAction>,
    hotkey: Option<KeyCode>,
    hover_text: Option<Text<'a>>,
    layer: usize,
}

impl<'a> Button<'a> {
    pub fn new(text: impl Into<String>) -> Self {
        Self {
            text: text.into(),
            selected: false,
            disabled: false,
            style: UiStyle::TEXT_SECONDARY,
            selected_style: UiStyle::HIGHLIGHT,
            block: None,
            on_click: None,
            hotkey: None,
            hover_text: None,
            layer: 0,
        }
    }

    pub fn selected(mut self, selected: bool) -> Self {
        self.selected = selected;
        self
    }

    pub fn disabled(mut self, disabled: bool) -> Self {
        self.disabled = disabled;
        self
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = style;
        self
    }

    pub fn selected_style(mut self, style: Style) -> Self {
        self.selected_style = style;
        self
    }

    pub fn block(mut self, block: Block<'a>) -> Self {
        self.block = Some(block);
        self
    }

    pub fn on_click(mut self, action: UiAction) -> Self {
        self.on_click = Some(action);
        self
    }

    pub fn hotkey(mut self, key: KeyCode) -> Self {
        self.hotkey = Some(key);
        self
    }

    pub fn hover_text(mut self, text: Text<'a>) -> Self {
        self.hover_text = Some(text);
        self
    }

    pub fn layer(mut self, layer: usize) -> Self {
        self.layer = layer;
        self
    }
}

impl Widget for Button<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let mut block = self.block.unwrap_or_else(Block::bordered);

        if self.selected {
            block = block
                .border_set(border::THICK)
                .border_style(UiStyle::HIGHLIGHT);
        } else {
            block = block.border_style(UiStyle::BORDER);
        }

        let text_style = if self.disabled {
            UiStyle::MUTED
        } else if self.selected {
            self.selected_style
        } else {
            self.style
        };

        Paragraph::new(Line::from(format!(" {} ", self.text)))
            .style(text_style)
            .block(block)
            .centered()
            .render(area, buf);
    }
}

#[derive(Debug, Default)]
pub struct ButtonState;

impl StatefulWidget for Button<'_> {
    type State = ButtonState;

    fn render(self, area: Rect, buf: &mut Buffer, _state: &mut Self::State) {
        Widget::render(self, area, buf);
    }
}

impl InteractiveWidget for Button<'_> {
    fn layer(&self) -> usize {
        self.layer
    }

    fn before_rendering(&mut self, area: Rect, registry: &mut CallbackRegistry) {
        if let Some(action) = self.on_click.clone() {
            registry.register_mouse_callback_on_layer(
                MouseEventKind::Down(MouseButton::Left),
                Some(area),
                action.clone(),
                self.layer,
            );

            if let Some(key) = self.hotkey {
                registry.register_keyboard_callback(key, action);
            }
        }
    }

    fn hover_text(&self) -> Text<'_> {
        self.hover_text.clone().unwrap_or_default()
    }
}

use ratatui::{
    Frame,
    layout::Rect,
    widgets::{StatefulWidget, Widget},
};

use super::{callback_registry::CallbackRegistry, traits::InteractiveWidget};

pub struct UiFrame<'a, 'b> {
    frame: &'a mut Frame<'b>,
    callback_registry: CallbackRegistry,
    hover_text_area: Rect,
    hover_text: Option<String>,
}

impl<'a, 'b> UiFrame<'a, 'b> {
    pub fn new(
        frame: &'a mut Frame<'b>,
        hover_text_area: Rect,
        mouse_position: Option<(u16, u16)>,
    ) -> Self {
        Self {
            frame,
            callback_registry: CallbackRegistry::with_mouse_position(mouse_position),
            hover_text_area,
            hover_text: None,
        }
    }

    pub fn render_widget<W: Widget>(&mut self, widget: W, area: Rect) {
        self.frame.render_widget(widget, area);
    }

    pub fn render_stateful_widget<W>(&mut self, widget: W, area: Rect, state: &mut W::State)
    where
        W: StatefulWidget,
    {
        self.frame.render_stateful_widget(widget, area, state);
    }

    pub fn render_interactive_widget<W: InteractiveWidget>(&mut self, mut widget: W, area: Rect) {
        let layer = widget.layer();
        let is_hovered = self.is_hovered(area, layer);
        if is_hovered && self.hover_text.is_none() {
            self.hover_text = Some(widget.hover_text().to_string());
        }

        widget.before_rendering(area, &mut self.callback_registry);
        widget.render(area, self.frame.buffer_mut());
    }

    pub fn render_stateful_interactive_widget<W>(
        &mut self,
        mut widget: W,
        area: Rect,
        state: &mut W::State,
    ) where
        W: StatefulWidget + InteractiveWidget,
    {
        let layer = widget.layer();
        let is_hovered = self.is_hovered(area, layer);
        if is_hovered && self.hover_text.is_none() {
            self.hover_text = Some(widget.hover_text().to_string());
        }

        widget.before_rendering(area, &mut self.callback_registry);
        self.frame.render_stateful_widget(widget, area, state);
    }

    pub fn set_active_layer(&mut self, layer: usize) {
        self.callback_registry.set_active_layer(layer);
    }

    pub fn is_hovered(&self, area: Rect, layer: usize) -> bool {
        self.callback_registry.active_layer() == layer && self.callback_registry.is_hovering(area)
    }

    pub fn area(&self) -> Rect {
        self.frame.area()
    }

    pub fn hover_text_area(&self) -> Rect {
        self.hover_text_area
    }

    pub fn registry_mut(&mut self) -> &mut CallbackRegistry {
        &mut self.callback_registry
    }

    pub fn hover_text(&self) -> Option<&str> {
        self.hover_text.as_deref()
    }

    pub fn into_registry(self) -> CallbackRegistry {
        self.callback_registry
    }
}

